{"content":"750: // The returned channel is closed when the (asynchronous) termination is finished.
751: func (s preparedGenericAPIServer) NonBlockingRunWithContext(ctx context.Context, shutdownTimeout time.Duration) (<-chan struct{}, <-chan struct{}, error) {
752: 	// Use an internal stop channel to allow cleanup of the listeners on error.
753: 	internalStopCh := make(chan struct{})
754: 	var stoppedCh <-chan struct{}
755: 	var listenerStoppedCh <-chan struct{}
756: 	if s.SecureServingInfo != nil && s.Handler != nil {
757: 		var err error
758: 		stoppedCh, listenerStoppedCh, err = s.SecureServingInfo.Serve(s.Handler, shutdownTimeout, internalStopCh)
759: 		if err != nil {
760: 			close(internalStopCh)
761: 			return nil, nil, err
762: 		}
763: 	}
764: 
765: 	// Now that listener have bound successfully, it is the
766: 	// responsibility of the caller to close the provided channel to
767: 	// ensure cleanup.
768: 	go func() {
769: 		<-ctx.Done()
770: 		close(internalStopCh)
771: 	}()
772: 
773: 	s.RunPostStartHooks(ctx)
774: 
775: 	if _, err := systemd.SdNotify(true, "READY=1\n"); err != nil {
776: 		klog.Errorf("Unable to send systemd daemon successful start message: %v\n", err)
777: 	}
778: 
779: 	return stoppedCh, listenerStoppedCh, nil
780: }
