782: // installAPIResources is a private method for installing the REST storage backing each api groupversionresource
783: func (s *GenericAPIServer) installAPIResources(apiPrefix string, apiGroupInfo *APIGroupInfo, typeConverter managedfields.TypeConverter) error {
784: 	var resourceInfos []*storageversion.ResourceInfo
785: 	for _, groupVersion := range apiGroupInfo.PrioritizedVersions {
786: 		if len(apiGroupInfo.VersionedResourcesStorageMap[groupVersion.Version]) == 0 {
787: 			klog.Warningf("Skipping API %v because it has no resources.", groupVersion)
788: 			continue
789: 		}
790: 
791: 		apiGroupVersion, err := s.getAPIGroupVersion(apiGroupInfo, groupVersion, apiPrefix)
792: 		if err != nil {
793: 			return err
794: 		}
795: 		if apiGroupInfo.OptionsExternalVersion != nil {
796: 			apiGroupVersion.OptionsExternalVersion = apiGroupInfo.OptionsExternalVersion
797: 		}
798: 		apiGroupVersion.TypeConverter = typeConverter
799: 		apiGroupVersion.MaxRequestBodyBytes = s.maxRequestBodyBytes
800: 
801: 		discoveryAPIResources, r, err := apiGroupVersion.InstallREST(s.Handler.GoRestfulContainer)
802: 
803: 		if err != nil {
804: 			return fmt.Errorf("unable to setup API %v: %v", apiGroupInfo, err)
805: 		}
806: 		resourceInfos = append(resourceInfos, r...)
807: 
808: 		// Aggregated discovery only aggregates resources under /apis
809: 		if apiPrefix == APIGroupPrefix {
810: 			s.AggregatedDiscoveryGroupManager.AddGroupVersion(
811: 				groupVersion.Group,
812: 				apidiscoveryv2.APIVersionDiscovery{
813: 					Freshness: apidiscoveryv2.DiscoveryFreshnessCurrent,
814: 					Version:   groupVersion.Version,
815: 					Resources: discoveryAPIResources,
816: 				},
817: 			)
818: 		} else {
819: 			// There is only one group version for legacy resources, priority can be defaulted to 0.
820: 			s.AggregatedLegacyDiscoveryGroupManager.AddGroupVersion(
821: 				groupVersion.Group,
822: 				apidiscoveryv2.APIVersionDiscovery{
823: 					Freshness: apidiscoveryv2.DiscoveryFreshnessCurrent,
824: 					Version:   groupVersion.Version,
825: 					Resources: discoveryAPIResources,
826: 				},
827: 			)
828: 		}
829: 
830: 	}
831: 
832: 	s.RegisterDestroyFunc(apiGroupInfo.destroyStorage)
833: 
834: 	if s.FeatureGate.Enabled(features.StorageVersionAPI) &&
835: 		s.FeatureGate.Enabled(features.APIServerIdentity) {
836: 		// API installation happens before we start listening on the handlers,
837: 		// therefore it is safe to register ResourceInfos here. The handler will block
838: 		// write requests until the storage versions of the targeting resources are updated.
839: 		s.StorageVersionManager.AddResourceInfo(resourceInfos...)
840: 	}
841: 
842: 	return nil
843: }
